def PolyTriangle(len: int, start: int, pos: bool) -> list[list[int]]:
    c = [[1], [0, start]]
    for i in range(2, len):
        row1 = [0] + c[i-1] if pos else [0] + [-v for v in c[i-1]]
        row2 = c[i-2] + [0, 0]
        row = [t1 + t2 for t1, t2 in zip(row1, row2)]
        c.append(row)
    return c
